#include <iostream>
#include <string>

// Function declaration (prototype)
int add(int a, int b);
void displayHealth(int health, int maxHealth);
std::string getPlayerStatus(int health);
int calculateDamage(int baseDamage, int modifier);

// Function definitions
int add(int a, int b) {
    return a + b;
}

void displayHealth(int health, int maxHealth) {
    std::cout << "Health: " << health << "/" << maxHealth << std::endl;
}

std::string getPlayerStatus(int health) {
    if (health > 75) {
        return "Healthy";
    } else if (health > 40) {
        return "Wounded";
    } else {
        return "Critical";
    }
}

int calculateDamage(int baseDamage, int modifier) {
    return baseDamage + modifier;
}

int main() {
    std::cout << "=== Functions in Action ===" << std::endl;

    // Using the add function
    int result = add(10, 5);
    std::cout << "10 + 5 = " << result << std::endl;

    // Player stats
    int playerHealth = 65;
    int maxHealth = 100;

    // Using displayHealth
    displayHealth(playerHealth, maxHealth);

    // Using getPlayerStatus
    std::string status = getPlayerStatus(playerHealth);
    std::cout << "Status: " << status << std::endl;

    // Using calculateDamage
    int damage = calculateDamage(15, 5);
    std::cout << "Damage dealt: " << damage << std::endl;

    // Applying damage
    playerHealth -= damage;
    displayHealth(playerHealth, maxHealth);
    std::cout << "Status: " << getPlayerStatus(playerHealth) << std::endl;

    return 0;
}

