phase3.solution:
#include <iostream>
#include <string>

int calculateAttack(int base, int bonus) {
    return base + bonus;
}

void displayStats(std::string name, int health, int attack) {
    std::cout << "Name: " << name << " | Health: " << health 
              << " | Attack: " << attack << std::endl;
}

std::string getRank(int level) {
    if (level < 5) {
        return "Novice";
    } else if (level < 10) {
        return "Adept";
    } else {
        return "Master";
    }
}

int main() {
    std::string name = "Hero";
    int health = 100;
    int attack = 15;
    int level = 7;

    displayStats(name, health, attack);

    int totalAttack = calculateAttack(attack, 5);
    std::cout << "Total Attack: " << totalAttack << std::endl;

    std::string rank = getRank(level);
    std::cout << "Rank: " << rank << std::endl;

    return 0;
}
